1	const PROCESSING_FEE = 5;
2	const BLOCK_SIZE = 3;
3	const BLOCK_PREMIUM = 60;
4	
5	const BASE_PREMIUMS: Record<string, number> = {
6	  sword: 100,
7	  amulet: 60,
8	  staff: 80,
9	  potion: 40,
10	  rune: 25,
11	  moonstone: 25,
12	};
13	
14	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
15	
16	export function claimOffice(request: any): any {
17	  const customer = request.customer;
18	  const results: any[] = [];
19	
20	  for (let stepIndex = 0; stepIndex < request.steps.length; stepIndex++) {
21	    const step = request.steps[stepIndex];
22	
23	    if (step.type === "claim") {
24	      const policyStep = request.steps[step.policy];
25	      const insuranceValues: Record<string, number> = {
26	        sword: 1000,
27	        amulet: 600,
28	        staff: 800,
29	        potion: 400,
30	        rune: 250,
31	        moonstone: 250,
32	      };
33	      let insuranceSum = 0;
34	      for (const item of policyStep.items) {
35	        insuranceSum += insuranceValues[item.type] || 0;
36	      }
37	      const cap = 2 * insuranceSum;
38	      let totalPayout = 0;
39	      for (const damage of step.incident.damages) {
40	        const matchedItem = policyStep.items.find((i: any) => i.type === damage.itemType);
41	        let reimbursement = damage.amount;
42	        if (matchedItem && matchedItem.enchantment >= 8) {
43	          reimbursement = damage.amount * 0.5;
44	        }
45	        totalPayout += reimbursement - 100;
46	      }
47	      results.push({ payout: totalPayout, remainingCap: cap - totalPayout });
48	      continue;
49	    }
50	
51	    const items = step.items;
52	
53	    const componentCounts: Record<string, number> = {};
54	    for (const item of items) {
55	      if (COMPONENT_TYPES.has(item.type)) {
56	        componentCounts[item.type] = (componentCounts[item.type] || 0) + 1;
57	      }
58	    }
59	
60	    let totalPremium = 0;
61	    let policyBasePremium = 0;
62	    const blocksApplied = new Set<string>();
63	
64	    for (const item of items) {
65	      if (!(item.type in BASE_PREMIUMS)) {
66	        throw new Error(`Unknown item type: ${item.type}`);
67	      }
68	      const isBlock = COMPONENT_TYPES.has(item.type) && componentCounts[item.type] === BLOCK_SIZE;
69	      if (isBlock && !blocksApplied.has(item.type)) {
70	        totalPremium += BLOCK_PREMIUM;
71	        policyBasePremium += BASE_PREMIUMS[item.type] * BLOCK_SIZE;
72	        blocksApplied.add(item.type);
73	      } else if (!isBlock) {
74	        let itemPremium = BASE_PREMIUMS[item.type];
75	        policyBasePremium += BASE_PREMIUMS[item.type];
76	        if (item.cursed) {
77	          itemPremium += BASE_PREMIUMS[item.type] * 0.5;
78	        }
79	        if (item.enchantment >= 5) {
80	          itemPremium += BASE_PREMIUMS[item.type] * 0.3;
81	        }
82	        totalPremium += itemPremium;
83	      }
84	    }
85	
86	    if (customer.yearsWithMHPCO >= 2) {
87	      totalPremium -= policyBasePremium * 0.2;
88	    }
89	
90	    totalPremium += policyBasePremium * 0.1;
91	
92	    if (stepIndex > 0) {
93	      totalPremium -= policyBasePremium * 0.15;
94	    }
95	
96	    results.push({ premium: Math.ceil(totalPremium + PROCESSING_FEE) });
97	  }
98	
99	  return results;
100	}
